function dfs(s, start, results, current) {
    if (start === s.length) {
        results.push([...current]);
        return;
    }

    for (let end = start; end < s.length; end++) {
        if (isPalindrome(s, start, end)) {
            current.push(s.slice(start, end + 1));
            dfs(s, end + 1, results, current);
            current.pop();
        }
    }
}

function partition(s) {
    let results = [];
    dfs(s, 0, results, []);
    return results;
}
